Ref: docs/harness-improvements.md #2","title":"ENH: Tool apply-patch / multi-edit + mejor feedback de error en edit"}

import { stdout } from "process";
import { AgentConfig } from "./agent-config.js";
import {
  pruneContext,
  truncateForContext,
  truncateForDisplay,
} from "./context-management.js";
import { logger } from "./logger.js";
import { Message, ToolMessage } from "./message.js";
import { LLMProvider, LLMResponse } from "./providers/llm-provider.js";

type RunnerConstructorProps = {
  llmProvider: LLMProvider;
  agentConfig: AgentConfig;
  maxSteps?: number;
  maxContextTokens?: number;
  signal?: AbortSignal;
  /** Si se provee, las invocaciones a la tool `ask_user` pausan el runner
   * y llaman a este callback. La respuesta se inyecta como tool_result. */
  onAskUser?: (question: string) => Promise<string>;
};

type RunnerEvent =
  | { type: "text"; text: string }
  | { type: "text_stream"; text: string }
  | { type: "text_stream_end" }
  | { type: "state"; message: Message }
  | { type: "tool_use"; name: string; input: unknown }
  | {
      type: "tool_result";
      output: string;
      /** Output completo (sin truncar) para poder mostrar un resumen real. */
      rawOutput?: string;
    }
  | { type: "ask_user"; question: string; toolId: string };

/** Estado mutable que comparten los métodos de un turno del loop. */
interface TurnState {
  textParts: string[];
  toolBlocks: Array<{ id: string; name: string; input: unknown }>;
  toolResults: ToolMessage[];
  stopReason: "end_turn" | "tool_use" | "max_tokens";
}

class Runner {
  // Métricas de una sola corrida (se resetean con resetMetrics()).
  // El acumulado histórico lo mantiene Session (addUsage), que es el
  // único dueño persistente del costo total.
  #llmProvider: LLMProvider;
  #agentConfig: AgentConfig;
  #maxSteps: number;
  #maxContextTokens: number;
  #signal: AbortSignal | undefined;
  #interrupted: boolean;
  #onAskUser: ((question: string) => Promise<string>) | undefined;
  #metrics: {
    totalInputTokens: number;
    totalOutputTokens: number;
    totalToolCalls: number;
    totalCost: number;
    startTime: number;
  };

  constructor({
    llmProvider,
    agentConfig,
    maxSteps = 15,
    maxContextTokens = 100_000,
    signal,
    onAskUser,
  }: RunnerConstructorProps) {
    this.#llmProvider = llmProvider;
    this.#agentConfig = agentConfig;
    this.#maxSteps = maxSteps;
    this.#maxContextTokens = maxContextTokens;
    this.#signal = signal;
    this.#interrupted = false;
    this.#onAskUser = onAskUser;
    this.#metrics = {
      totalInputTokens: 0,
      totalOutputTokens: 0,
      totalToolCalls: 0,
      totalCost: 0,
      startTime: Date.now(),
    };
  }

  /** Expone si el runner fue interrumpido (SIGINT) — el caller lo usa para
   * saber si debe guardar métricas parciales o descartarlas. */
  get interrupted(): boolean {
    return this.#interrupted;
  }

  // ── helpers ────────────────────────────────────────────────────────

  /**
   * Arma el contenido del mensaje assistant a partir de lo producido
   * en el turno. Si no hay nada visible, pone un fallback.
   */
  #buildAssistantContent(state: TurnState): Message["content"] {
    const content: Message["content"] = [];
    if (state.textParts.length > 0) {
      content.push({ type: "text", text: state.textParts.join("") });
    }
    for (const tb of state.toolBlocks) {
      content.push({
        type: "tool_use",
        id: tb.id,
        name: tb.name,
        input: tb.input,
      });
    }
    if (content.length === 0) {
      content.push({
        type: "text",
        text: "(El modelo no produjo contenido visible en este turno)",
      });
    }
    return content;
  }

  /** Construye el snapshot del estado vacío para un turno nuevo. */
  #newTurnState(): TurnState {
    return {
      textParts: [],
      toolBlocks: [],
      toolResults: [],
      stopReason: "end_turn",
    };
  }

  // ── fases del turno ────────────────────────────────────────────────

  /** Llama al LLM (stream o no-stream), emite eventos y llena `state`. */
  async *#callLLM(
    prunedContext: Message[],
    state: TurnState,
  ): AsyncGenerator<RunnerEvent> {
    const hasStream = typeof this.#llmProvider.callStream === "function";

    if (hasStream) {
      const stream = this.#llmProvider.callStream(
        prunedContext,
        this.#agentConfig,
        this.#signal,
      );

      for await (const event of stream) {
        if (event.type === "text") {
          state.textParts.push(event.text);
          yield { type: "text_stream", text: event.text };
        } else if (event.type === "tool_use") {
          state.toolBlocks.push({
            id: event.id,
            name: event.name,
            input: event.input,
          });
        } else if (event.type === "done") {
          state.stopReason = event.stop_reason;
          this.#metrics.totalInputTokens += event.usage.input_tokens;
          this.#metrics.totalOutputTokens += event.usage.output_tokens;
          this.#metrics.totalCost += event.cost;
        }
      }

      if (state.textParts.length > 0) {
        yield { type: "text_stream_end" };
      }
    } else {
      const data: LLMResponse = await this.#llmProvider.call(
        prunedContext,
        this.#agentConfig,
        this.#signal,
      );

      this.#metrics.totalInputTokens += data.usage.input_tokens;
      this.#metrics.totalOutputTokens += data.usage.output_tokens;
      this.#metrics.totalCost += data.cost;

      for (const block of data.content) {
        if (block.type === "text") {
          state.textParts.push(block.text);
          yield { type: "text", text: block.text };
        }
        if (block.type === "tool_use") {
          state.toolBlocks.push({
            id: block.id,
            name: block.name,
            input: block.input,
          });
        }
      }

      state.stopReason = data.stop_reason;
    }
  }

  /** Ejecuta las tool calls pendientes, emite eventos y llena `state.toolResults`. */
  async *#executeTools(state: TurnState): AsyncGenerator<RunnerEvent> {
    for (const block of state.toolBlocks) {
      if (block.name === "ask_user") {
        yield* this.#handleAskUser(block, state);
        continue;
      }

      this.#metrics.totalToolCalls++;

      const tool = this.#agentConfig.getTool(block.name);
      if (!tool) {
        yield* this.#handleUnknownTool(block.name, block.id, state);
        continue;
      }

      yield { type: "tool_use", name: tool.name, input: block.input };

      yield* this.#handleToolExecution(tool.name, block.id, block.input, state);
    }
  }

  // ── sub-fases de executeTools ──────────────────────────────────────

  async *#handleAskUser(
    block: { id: string; name: string; input: unknown },
    state: TurnState,
  ): AsyncGenerator<RunnerEvent> {
    if (!this.#onAskUser) return;

    const question =
      (block.input as { question?: string }).question ?? "¿Continuar?";
    yield { type: "ask_user", question, toolId: block.id };

    const answer = await this.#onAskUser(question);
    const output = answer || "(sin respuesta)";
    yield {
      type: "tool_result",
      output: "(confirmación recibida)",
      rawOutput: output,
    };
    state.toolResults.push({
      type: "tool_result",
      tool_use_id: block.id,
      content: output,
      is_error: false,
    });
  }

  async *#handleUnknownTool(
    name: string,
    toolId: string,
    state: TurnState,
  ): AsyncGenerator<RunnerEvent> {
    const output = `Error: unknown tool "${name}"`;
    logger.error(output);
    yield { type: "tool_result", output };
    state.toolResults.push({
      type: "tool_result",
      tool_use_id: toolId,
      content: output,
      is_error: true,
    });
  }

  async *#handleToolExecution(
    toolName: string,
    toolId: string,
    input: unknown,
    state: TurnState,
  ): AsyncGenerator<RunnerEvent> {
    const tool = this.#agentConfig.getTool(toolName)!;
    let output: string;
    let isError = false;
    try {
      output = tool.execute(input) as string;
    } catch (err: unknown) {
      isError = true;
      output = `Error executing tool "${toolName}": ${err instanceof Error ? err.message : String(err)}`;
      logger.error("Tool execution threw", { tool: toolName, error: output });
    }

    const shown = truncateForDisplay(output);
    const forModel = truncateForContext(output, this.#maxContextTokens);

    yield { type: "tool_result", output: shown, rawOutput: output };
    state.toolResults.push({
      type: "tool_result",
      tool_use_id: toolId,
      content: forModel,
      is_error: isError,
    });
  }

  // ── loop principal ─────────────────────────────────────────────────

  async *run(incomingContext: readonly Message[]): AsyncGenerator<RunnerEvent> {
    const workingContext = [...incomingContext];
    logger.info(`Starting runner with max steps: ${this.#maxSteps}`);

    let steps = this.#maxSteps;
    while (steps > 0) {
      if (this.#signal?.aborted) {
        this.#interrupted = true;
        logger.info("Runner interrupted by abort signal");
        yield { type: "text", text: "⏹ Interrumpido por el usuario." };
        break;
      }

      const prunedContext = pruneContext(
        workingContext,
        this.#maxContextTokens,
      );

      const state = this.#newTurnState();

      try {
        yield* this.#callLLM(prunedContext, state);
      } catch (err: unknown) {
        if (err instanceof Error && err.name === "AbortError") {
          this.#interrupted = true;
          logger.info("LLM call aborted by signal");
          yield { type: "text", text: "⏹ Interrumpido por el usuario." };
          const partialMessage: Message = {
            role: "assistant",
            content: this.#buildAssistantContent(state),
          };
          workingContext.push(partialMessage);
          yield { type: "state", message: partialMessage };
          break;
        }
        throw err;
      }

      // Agregar mensaje assistant al contexto
      const assistantMessage: Message = {
        role: "assistant",
        content: this.#buildAssistantContent(state),
      };
      workingContext.push(assistantMessage);
      yield { type: "state", message: assistantMessage };

      // Ejecutar tools
      yield* this.#executeTools(state);

      if (state.toolResults.length > 0) {
        const toolMessage: Message = {
          role: "user",
          content: state.toolResults,
        };
        workingContext.push(toolMessage);
        yield { type: "state", message: toolMessage };
      }

      if (state.stopReason === "max_tokens") {
        logger.warn("Respuesta cortada por max_tokens");
        yield {
          type: "text",
          text: "⚠ La respuesta se cortó (max_tokens). Subí el límite o pedí algo más chico.",
        };
        break;
      }

      if (state.stopReason === "end_turn") {
        logger.info("Agent finished (end_turn)");
        break;
      }

      steps--;
      if (steps === 0) {
        logger.warn(`Max steps reached (${this.#maxSteps})`);
      }
    }
  }

  getMetrics() {
    return {
      ...this.#metrics,
      durationMs: Date.now() - this.#metrics.startTime,
    };
  }

  resetMetrics() {
    this.#metrics = {
      totalInputTokens: 0,
      totalOutputTokens: 0,
      totalToolCalls: 0,
      totalCost: 0,
      startTime: Date.now(),
    };
  }
}

export { Runner, RunnerEvent };

import { AgentConfig } from "../agent-config.js";
import { Message } from "../message.js";

type LLMProviderConstructorProps = {
  apiKey: string;
  url: string;
};

// ── Tipos compartidos entre providers ────────────────────────────────────────

type TextBlock = { type: "text"; text: string };
type ToolUseBlock = { type: "tool_use"; id: string; name: string; input: unknown };
type Block = TextBlock | ToolUseBlock;

type LLMResponse = {
  content: Block[];
  stop_reason: "end_turn" | "tool_use" | "max_tokens";
  usage: { input_tokens: number; output_tokens: number };
  cost: number; // USD
};

/** Eventos que emite el stream de callStream */
type StreamEvent =
  | { type: "text"; text: string }
  | { type: "tool_use"; id: string; name: string; input: unknown }
  | {
      type: "done";
      stop_reason: "end_turn" | "tool_use" | "max_tokens";
      usage: { input_tokens: number; output_tokens: number };
      cost: number;
    };

// ── Precios OpenRouter por millón de tokens (USD) ────────────────────────────

const MODEL_PRICING: Record<string, { input: number; output: number }> = {
  // Claude 4 / 4.5
  "anthropic/claude-haiku-4-5": { input: 0.80, output: 4.00 },
  "anthropic/claude-sonnet-4": { input: 3.00, output: 15.00 },
  "anthropic/claude-opus-4": { input: 15.00, output: 75.00 },
  // Claude 3.5
  "anthropic/claude-3.5-haiku": { input: 0.80, output: 4.00 },
  "anthropic/claude-3.5-sonnet": { input: 3.00, output: 15.00 },
  "anthropic/claude-3-opus": { input: 15.00, output: 75.00 },
};

function calculateCost(model: string, inputTokens: number, outputTokens: number): number {
  let pricing = MODEL_PRICING[model];
  if (!pricing) {
    for (const [key, p] of Object.entries(MODEL_PRICING)) {
      // Match exacto de la clave completa
      if (model === key) {
        pricing = p;
        break;
      }
      // Match por prefijo: el modelo empieza con la clave (ej: "anthropic/claude-...")
      if (model.startsWith(key)) {
        pricing = p;
        break;
      }
      // Match sin el prefijo del proveedor: "claude-haiku-4-5" vs "anthropic/claude-haiku-4-5"
      const afterSlash = key.includes("/") ? key.split("/").slice(1).join("/") : key;
      if (model.startsWith(afterSlash)) {
        pricing = p;
        break;
      }
    }
  }
  if (!pricing) return 0; // modelo desconocido, no estimamos

  const inputCost = (inputTokens / 1_000_000) * pricing.input;
  const outputCost = (outputTokens / 1_000_000) * pricing.output;
  return inputCost + outputCost;
}

// ── Provider abstracto ───────────────────────────────────────────────────────

abstract class LLMProvider {
  #apiKey: string;
  #url: string;

  constructor({ apiKey, url }: LLMProviderConstructorProps) {
    this.#apiKey = apiKey;
    this.#url = url;
  }

  protected apiKey() {
    return this.#apiKey;
  }

  protected url() {
    return this.#url;
  }

  abstract call(messages: Message[], agent: AgentConfig, signal?: AbortSignal): Promise<LLMResponse>;

  /** Versión streaming: devuelve un async generator de eventos. */
  abstract callStream(
    messages: Message[],
    agent: AgentConfig,
    signal?: AbortSignal,
  ): AsyncGenerator<StreamEvent>;
}

export { Block, LLMProvider, LLMResponse, StreamEvent, TextBlock, ToolUseBlock, calculateCost };

